mapper.select:
select r.id, r.requirement_code, r.title, r.requirement_type, r.priority, r.status, r.description, r.wbs_id, w.node_name as wbs_name, r.proposer_id, u.real_name as proposer_name, r.created_at from requirement_info r left join wbs_node w on w.id = r.wbs_id left join sys_user u on u.id = r.proposer_id where r.project_id = #{projectId} and r.is_deleted = 0
and r.requirement_type = #{query.type}
and r.priority = #{query.priority}
and r.status = #{query.status}
order by r.created_at desc

mapper.insert:
insert into requirement_info (
    id, project_id, wbs_id, requirement_code, title, requirement_type, priority, status,
    description, proposer_id, created_by, created_at, updated_by, updated_at, is_deleted
) values (
    #{id}, #{projectId}, #{wbsId}, #{requirementCode}, #{title}, #{requirementType}, #{priority}, #{status},
    #{description}, #{proposerId}, #{createdBy}, #{createdAt}, #{updatedBy}, #{updatedAt}, #{deleted}
)
